/*
 * @method
 * @name apex#fetchTime
 * @description fetches the current integer timestamp in milliseconds from the exchange server
 * @see https://api-docs.pro.apex.exchange/#publicapi-v3-for-omni-get-system-time-v3
 * @param {object} [params] extra parameters specific to the exchange API endpoint
 * @returns {int} the current integer timestamp in milliseconds from the exchange server
 */
    pub async fn fetch_time(&mut self, optional_args: &[Value]) -> Value {
        let mut params = get_arg(optional_args, 0, Value::Map({
    let mut m = indexmap::IndexMap::new();
    m
}));
        let mut response: Value = self.public_get_v3_time(&[params.clone()]).await;
        let mut data: Value = self.safe_dict_k(response.clone(), "data", &[Value::Map({
    let mut m = indexmap::IndexMap::new();
    m
})]);
        return self.safe_integer_k(data.clone(), "time", &[]);

    Value::Null
}

    pub fn parse_balance(&self, mut response: Value) -> Value {
        //
        // {
        //     "totalEquityValue": "100.000000",
        //     "availableBalance": "100.000000",
        //     "initialMargin": "100.000000",
        //     "maintenanceMargin": "100.000000",
        //     "symbolToOraclePrice": {
        //     "BTC-USDC": {
        //         "oraclePrice": "20000",
        //             "createdTime": 124566
        //     }
        // }
        // }
        //
        let mut timestamp: Value = self.milliseconds();
        let mut result: Value = Value::Map({
            let mut m = indexmap::IndexMap::new();
                m.insert("info".to_string(), response.clone());
                m.insert("timestamp".to_string(), timestamp.clone());
                m.insert("datetime".to_string(), self.iso8601(timestamp.clone()));
            m
        });
        let mut code: Value = Value::Str("USDT".to_string());
        let mut account: Value = self.account();
        add_element_to_object(&mut account, &Value::Str("free".to_string()), self.safe_string_k(response.clone(), "availableBalance", &[]));
        add_element_to_object(&mut account, &Value::Str("total".to_string()), self.safe_string_k(response.clone(), "totalEquityValue", &[]));
        add_element_to_object(&mut result, &code, account.clone());
        return self.safe_balance(result.clone());

    Value::Null
}

/*
 * @method
 * @name apex#fetchBalance
 * @description query for account info
 * @see https://api-docs.pro.apex.exchange/#privateapi-v3-for-omni-get-retrieve-user-account-balance
 * @param {object} [params] extra parameters specific to the exchange API endpoint
 * @returns {object} a [balance structure]{@link https://docs.ccxt.com/?id=balance-structure}
 */
    pub async fn fetch_balance(&mut self, optional_args: &[Value]) -> Value {
        let mut params = get_arg(optional_args, 0, Value::Map({
    let mut m = indexmap::IndexMap::new();
    m
}));
        self.load_markets(&[]).await;
        let mut response: Value = self.private_get_v3_account_balance(&[params.clone()]).await;
        let mut data: Value = self.safe_dict_k(response.clone(), "data", &[Value::Map({
    let mut m = indexmap::IndexMap::new();
    m
})]);
        return self.parse_balance(data.clone());

    Value::Null
}

    pub fn parse_account(&self, mut account: Value) -> Value {
        let mut accountId: Value = self.safe_string_k(account.clone(), "id", &[Value::Str("0".to_string())]);
        return Value::Map({
    let mut m = indexmap::IndexMap::new();
        m.insert("id".to_string(), accountId.clone());
        m.insert("type".to_string(), Value::Null);
        m.insert("code".to_string(), Value::Null);
        m.insert("info".to_string(), account.clone());
    m
});

    Value::Null
}

